SELECT project_name
FROM projects
ORDER BY project_name;

SELECT task_name
FROM project_tasks
WHERE status = 'open' AND priority = 'high';

SELECT COUNT(*) AS open_task_count
FROM project_tasks
WHERE project_id = 1 AND status = 'open';

SELECT name
FROM contacts
WHERE contact_type = (SELECT type_id FROM contact_types WHERE type_name = 'investor');

SELECT project_name
FROM projects
ORDER BY project_name;

SELECT project_name
FROM projects
WHERE status = 'pending';

SELECT assigned_to, COUNT(*) AS total_tasks
FROM project_tasks
GROUP BY assigned_to;

SELECT interaction_type
FROM interaction_logs
WHERE user_id = 1;
